<?php
declare(strict_types=1);require_once __DIR__.'/../app/email_marketing.php';proteger_admin();$pdo=getPDO();email_marketing_ensure_schema($pdo);$id=max(0,(int)($_GET['id']??$_POST['id']??0));$csrf=email_admin_csrf();$error='';if($_SERVER['REQUEST_METHOD']==='POST')try{email_check_csrf();$id=email_template_save($pdo,$_POST,(string)($_SESSION['equipe_nome']??'Administrador'));header('Location: email_editor.php?id='.$id.'&saved=1');exit;}catch(Throwable $e){$error=$e->getMessage();}$template=['name'=>'','subject'=>'','preheader'=>'','html_content'=>'<div style="max-width:600px;margin:auto;padding:24px;font-family:Arial,sans-serif"><h1>Olá, {{nome}}</h1><p>Escreva seu e-mail aqui.</p><p><a href="'.email_h(BASE_URL).'/trilha.php" style="background:#facc15;color:#111827;padding:12px 18px;border-radius:8px;text-decoration:none;display:inline-block">Acessar área de membros</a></p><p style="font-size:12px;color:#64748b;text-align:center"><a href="{{amazonSESUnsubscribeUrl}}">Descadastrar-se destes e-mails</a></p></div>'];if($id){$st=$pdo->prepare('SELECT t.*,v.html_content FROM email_templates t LEFT JOIN email_template_versions v ON v.id=t.current_version_id WHERE t.id=:id');$st->execute(['id'=>$id]);$template=$st->fetch(PDO::FETCH_ASSOC)?:$template;}$menu='email_marketing';$page_title='Editor de e-mail';include __DIR__.'/_header.php';echo email_admin_styles();?><style>.editor-layout{display:grid;grid-template-columns:180px minmax(320px,1fr) 270px;gap:12px}.editor-palette button{display:block;width:100%;margin:6px 0;padding:9px;background:var(--bg);border:1px solid var(--border);border-radius:8px;color:var(--text);text-align:left}.editor-canvas{background:#e5e7eb;padding:25px;min-height:560px}.editor-canvas [contenteditable]{max-width:600px;min-height:480px;margin:auto;background:white;color:#111827;padding:20px;box-shadow:0 4px 20px #0002}.editor-code{font-family:monospace;min-height:280px!important}@media(max-width:950px){.editor-layout{grid-template-columns:1fr}.editor-palette{display:flex;flex-wrap:wrap;gap:5px}.editor-palette button{width:auto}}</style><div class="em"><div class="em-head"><div><h1>Editor de e-mail</h1><p class="text-muted">Arraste a ideia, edite no canvas ou use HTML completo.</p></div><a class="btn btn-ghost" href="email_modelos.php">← Modelos</a></div><?=email_admin_nav('templates')?><?php if(isset($_GET['saved'])):?><div class="em-msg">Nova versão salva.</div><?php endif?><?php if($error):?><div class="em-msg em-error"><?=email_h($error)?></div><?php endif?><form method="post" id="editorForm"><input type="hidden" name="csrf" value="<?=email_h($csrf)?>"><input type="hidden" name="id" value="<?=$id?>"><input type="hidden" name="html" id="htmlField"><div class="editor-layout"><aside class="em-card editor-palette"><h2>Inserir bloco</h2><button type="button" data-block="h2">Título</button><button type="button" data-block="p">Texto</button><button type="button" data-block="button">Botão</button><button type="button" data-block="image">Imagem</button><button type="button" data-block="divider">Divisor</button><button type="button" data-block="space">Espaço</button><button type="button" data-block="unsubscribe">Descadastro</button></aside><main class="editor-canvas"><div id="visual" contenteditable="true"><?=$template['html_content']?></div></main><aside class="em-card em-form"><h2>Configuração</h2><label>Nome interno<input name="name" value="<?=email_h($template['name'])?>" required></label><label>Assunto<input name="subject" value="<?=email_h($template['subject'])?>" required></label><label>Preheader<input name="preheader" value="<?=email_h($template['preheader']??'')?>"></label><button class="btn btn-primary" type="submit">Salvar nova versão</button><button class="btn btn-ghost" type="button" id="toggleCode">Editar HTML/CSS</button><textarea class="editor-code" id="code" hidden></textarea><small class="text-muted">Variáveis: {{nome}}, {{email}}, {{turma}}, {{link_area_membros}}.</small></aside></div></form></div><script>(()=>{const v=document.getElementById('visual'),code=document.getElementById('code'),field=document.getElementById('htmlField');const blocks={h2:'<h2>Novo título</h2>',p:'<p>Digite seu texto aqui.</p>',button:'<p><a href="https://" style="display:inline-block;padding:12px 18px;background:#facc15;color:#111827;border-radius:8px;text-decoration:none">Clique aqui</a></p>',image:'<p><img src="https://" alt="Descrição da imagem" style="max-width:100%;height:auto"></p>',divider:'<hr style="border:0;border-top:1px solid #e5e7eb">',space:'<div style="height:24px"></div>',unsubscribe:'<p style="font-size:12px;text-align:center"><a href="{{amazonSESUnsubscribeUrl}}">Descadastrar-se destes e-mails</a></p>'};document.querySelectorAll('[data-block]').forEach(b=>b.onclick=()=>{v.insertAdjacentHTML('beforeend',blocks[b.dataset.block]);v.focus()});document.getElementById('toggleCode').onclick=()=>{if(code.hidden){code.value=v.innerHTML;code.hidden=false}else{v.innerHTML=code.value;code.hidden=true}};document.getElementById('editorForm').onsubmit=()=>{if(!code.hidden)v.innerHTML=code.value;field.value=v.innerHTML}})();</script><?php include __DIR__.'/_footer.php';
